var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말해, 멋대로 소원구슬을 써먹고 껍데기만 가져왔다는 거군요.","JPN":"つまり、勝手に願い玉を使って抜け殻状態にしたものだけ持ってきたということですね。","ENG":"In other words, you used up the Wishing Ball without permission and brought its empty shell.","TWN":"所以，是徐芸擅自用了許願珠，然後只拿回來了一個空殼子。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 요망한 도둑고양이가!","JPN":"このずうずうしい泥棒猫！","ENG":"You sneaky stray cat!","TWN":"這個奸詐的野貓！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이를 어쩌죠, 부사장님? 전 기억이 하~나도 안 나는데요?","JPN":"どうしましょう、副社長？　私はぜーんぜんなーんにも思い出せません。","ENG":"Sorry, Vice President. I can't remember A SINGLE thing.","TWN":"什麼啊，副總？我完~全記不起來了呢？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"스카이라고 했나요. 참 신기하고 유용한 능력이네요.","JPN":"スカイって言いましたっけ？　本当に不思議で有用な能力ですね。","ENG":"That girl, Sky? What a mysterious yet useful ability she has.","TWN":"絲凱嗎？真是既神奇又有用的能力啊。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"불필요한 기억까지 깨끗이 지워 준다니 말이죠.","JPN":"不要な記憶まできれいさっぱり消してくれるなんて。","ENG":"She completely wiped out any unnecessary memories.","TWN":"連不必要的記憶都能清除乾淨。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"두통약...... 두통약이 필요해......","JPN":"頭痛薬……頭痛薬が必要よ……","ENG":"Pills... I need pills for my headache...","TWN":"止痛藥……我需要止痛藥……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"재미있군. 상시적인 인식 저해 능력이라니.","JPN":"面白いな。常時的な認識阻害能力か。","ENG":"Interesting. Disrupting other people's perception all the time...","TWN":"真有趣，居然有常態性的認知阻礙能力。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"과거에도 찾아보기 힘든 희귀하고 강력한 능력이야.","JPN":"過去の事例でも見かけない、珍しくて強力な能力だ。","ENG":"That's a very rare and powerful ability without precedent.","TWN":"那可是很罕見的強大能力呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 자네가 제안한 마지막 소원은 대체 뭐였나?","JPN":"それで君が提案した最後の願いはいったい何だったんだ？","ENG":"So what was the last wish you suggested?","TWN":"所以，你提議的最後願望到底是什麼？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 시점에서 소원구슬의 힘은 거의 사라져서 스카이라는 학생의 문제를 완전히 고치기엔 부족했을 텐데?","JPN":"あの時点で願い玉の力はほとんど無くなって、\\nスカイという子の問題を完全に解決するには足りなかったはずだが。","ENG":"The remaining power of the Wishing Ball must have been insufficient to solve Sky's problem.","TWN":"那時許願珠的力量幾乎已經耗盡了，完全解決那個叫絲凱的學生的問題應該不夠吧？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"일이 끝나고 스카이에게 전해 들었어. 정말 기발한 방법이었지.","JPN":"仕事が終わってからスカイから聞いたの。本当に奇抜な方法だったわ。","ENG":"Sky told me after everything was over. It was a brilliant idea.","TWN":"事情結束後我聽絲凱說了，真的是一個很奇妙的方法。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"서윤은 그걸 기억하지 못할 테니까 내가 말해줄게.","JPN":"シズカはそれを覚えていないから、私から話してあげるわね。","ENG":"Since Seo Yoon doesn't remember it, I'll tell you what happened.","TWN":"徐芸應該不記得了，我來說吧。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그러니까, 그게 뭐였냐면......","JPN":"だから、それはつまり……","ENG":"Their wish was...","TWN":"那個，方法就是……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"자, 오늘 수업은 여기까지!","JPN":"じゃあ、今日の授業はここまで！","ENG":"Okay, that's it for today!","TWN":"好了，今天的課就到這裡了！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"돌아갈 때는 다들 빗길 조심하렴.","JPN":"帰る時はみんな雨道に気を付けようね。","ENG":"It's raining outside. Be careful on the slippery roads.","TWN":"回去時大家小心雨路濕滑。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"고맙습니다, 선생님!","JPN":"ありがとうございました、先生！","ENG":"Thank you, ma'am!","TWN":"謝謝老師！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"고맙습니다, 선생님!","JPN":"ありがとうございました、先生！","ENG":"Thank you, ma'am!","TWN":"謝謝老師！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};